int encontrarRepetido(vector<int>& v, int inicio, int fin) {
    if (inicio >= fin) return -1; // Caso base
    int mitad = (inicio + fin) / 2;
    // Particionar y decidir en qué mitad buscar
    // Llamada recursiva
    return encontrarRepetido(v, inicio, mitad); // o encontrarRepetido(v, mitad + 1, fin);
}
